import pytest
import uuid
from <helper_fn> import api_client, reset_rate_limit

def test_single_pin_change_returns_200(auth_token, fresh_card):
    card_id = fresh_card["id"]
    reset_rate_limit(card_id, auth_token)
    idempotency_key = str(uuid.uuid4())
    headers = {
        "Authorization": f"Bearer {auth_token}",
        "Idempotency-Key": idempotency_key,
    }
    payload = {"new_pin": "1234"}
    resp = api_client().patch(
        f"/cards/{card_id}/pin",
        json=payload,
        headers=headers,
    )
    assert resp.status_code in (200, 204), (
        f"Expected 200/204, got {resp.status_code}: {resp.text}"
    )
    if resp.status_code == 200:
        body = resp.json()
        assert "error" not in body

import pytest
import uuid
from <helper_fn> import api_client, reset_rate_limit

def test_sixth_pin_change_returns_429(auth_token, fresh_card):
    card_id = fresh_card["id"]
    reset_rate_limit(card_id, auth_token)
    client = api_client()
    headers_base = {"Authorization": f"Bearer {auth_token}"}
    for i in range(5):
        hdrs = {**headers_base, "Idempotency-Key": str(uuid.uuid4())}
        r = client.patch(f"/cards/{card_id}/pin", json={"new_pin": f"{1000+i}"}, headers=hdrs)
        assert r.status_code in (200, 204), f"Change {i+1} failed: {r.status_code}"
    hdrs_sixth = {**headers_base, "Idempotency-Key": str(uuid.uuid4())}
    resp = client.patch(f"/cards/{card_id}/pin", json={"new_pin": "9999"}, headers=hdrs_sixth)
    assert resp.status_code == 429, (
        f"Expected 429 on 6th attempt, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert any(k in body for k in ("error", "message", "code")), (
        f"Expected error body, got: {body}"
    )

import pytest
import uuid
from <helper_fn> import api_client, reset_rate_limit

def test_exactly_five_pin_changes_all_succeed(auth_token, fresh_card):
    card_id = fresh_card["id"]
    reset_rate_limit(card_id, auth_token)
    client = api_client()
    headers_base = {"Authorization": f"Bearer {auth_token}"}
    results = []
    for i in range(5):
        hdrs = {**headers_base, "Idempotency-Key": str(uuid.uuid4())}
        r = client.patch(f"/cards/{card_id}/pin", json={"new_pin": f"{2000+i}"}, headers=hdrs)
        results.append(r.status_code)
    assert all(s in (200, 204) for s in results), (
        f"Expected all 5 changes to succeed; statuses: {results}"
    )
    assert 429 not in results, (
        f"Unexpected 429 within allowed quota; statuses: {results}"
    )

import pytest
import uuid
from <helper_fn> import api_client

def test_pin_change_rejected_for_card_not_owned_by_caller(auth_token, foreign_card):
    foreign_card_id = foreign_card["id"]
    client = api_client()
    headers = {
        "Authorization": f"Bearer {auth_token}",
        "Idempotency-Key": str(uuid.uuid4()),
    }
    payload = {"new_pin": "0000"}
    resp = client.patch(f"/cards/{foreign_card_id}/pin", json=payload, headers=headers)
    assert resp.status_code in (403, 404), (
        f"Expected 403 or 404 for non-owned card, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert any(k in body for k in ("error", "message", "detail")), (
        f"Expected error body, got: {body}"
    )
